  ('optician-moex-02181', 'optician', 'optician-moex-107-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '對於近視隱形眼鏡與框架眼鏡之比較，下列何者錯誤？', '["看近處的物體，戴隱形眼鏡比戴框架眼鏡須更多的調節力（accommodation）和聚合力（convergence）", "戴框架眼鏡所形成的視網膜影像尺寸，大於戴隱形眼鏡所形成的視網膜影像尺寸", "戴隱形眼鏡比戴框架眼鏡，較不會產生在光學上的稜鏡效應", "軸性屈光異常（axial ametropia）戴隱形眼鏡幫助較少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "4938abf70e8e", "answer_pdf_sha1": "53d5934cfce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
